SELECT AVG(dogs.current_weight) AS average_weight
FROM dogs
WHERE dogs.dog_id IN (SELECT dog_id FROM feeding_plans);

SELECT p.product_name
FROM products p
WHERE p.product_id IN (
  SELECT o.product_id
  FROM orders o
  WHERE o.order_id IN (
    SELECT py.order_id
    FROM payments py
  )
);

SELECT breed_name, average_weight 
FROM dog_breeds 
WHERE suitable_for = 'Families';

SELECT breed_name, lifespan AS average_lifespan
FROM dog_breeds
ORDER BY lifespan DESC;

SELECT name, current_weight 
FROM dogs 
WHERE current_weight = (SELECT MAX(current_weight) FROM dogs);

SELECT breed_name
FROM dog_breeds
WHERE lifespan = (SELECT MAX(lifespan) FROM dog_breeds);

SELECT breed_name
FROM dog_breeds
WHERE average_weight = (SELECT MAX(average_weight) FROM dog_breeds);

SELECT AVG(calorie_intake) AS average_daily_calorie_intake
FROM nutrition_recommendations
WHERE age = '3 weeks' AND health_conditions = 'None';
